:host{display:block;width:100%;--_bg:var(--ov-bg,#fff);--_raised:var(--ov-bg,#fff);--_text:var(--ov-text,#1f2933);--_muted:var(--ov-muted,#6b7280);--_line:var(--ov-line,#e5e7eb);--_accent:var(--ov-accent,#4f46e5);--_ok:var(--ov-ok,#0f9d58);--_no:var(--ov-no,#e11d48);--_partial:var(--ov-partial,#d97706);--_soft:#f8fafc;--_group:#f3f4f6;--_accent-soft:#eef2ff;--_hover:#f8fafc;color:var(--_text);font-family:ui-sans-serif,system-ui,-apple-system,BlinkMacSystemFont,'Segoe UI',sans-serif;-webkit-font-smoothing:antialiased}
:host([hidden]){display:none}
*{box-sizing:border-box}

.frame{overflow:hidden;border:1px solid var(--_line);border-radius:18px;background:var(--_bg);box-shadow:0 12px 32px rgba(15,23,42,.07)}
.cover{position:relative;min-height:170px;overflow:hidden;background:linear-gradient(135deg,var(--_accent),color-mix(in srgb,var(--_accent) 55%,#06b6d4))}
.cover img{display:block;width:100%;height:190px;object-fit:cover}
.cover:after{content:'';position:absolute;inset:auto 0 0;height:55%;background:linear-gradient(transparent,rgba(15,23,42,.38));pointer-events:none}
.content{display:grid;grid-template-columns:88px minmax(0,1fr);gap:20px;padding:24px}
.date-badge{overflow:hidden;align-self:start;border:1px solid var(--_line);border-radius:15px;background:var(--_raised);text-align:center;box-shadow:0 8px 20px rgba(15,23,42,.06)}
.month{display:block;padding:7px;background:var(--_accent);color:#fff;font-size:10px;font-weight:850;letter-spacing:.12em;text-transform:uppercase}
.day{display:block;padding:8px 4px 2px;color:var(--_text);font-family:ui-monospace,SFMono-Regular,Menlo,Monaco,Consolas,'Liberation Mono',monospace;font-size:30px;font-weight:850;font-variant-numeric:tabular-nums;line-height:1}
.weekday{display:block;padding:4px 4px 9px;color:var(--_muted);font-size:10px;font-weight:700}
.eyebrow{margin:0 0 6px;color:var(--_accent);font-size:10px;font-weight:800;letter-spacing:.12em;text-transform:uppercase}
h2{margin:0;color:var(--_text);font-size:clamp(21px,3vw,29px);font-weight:780;letter-spacing:-.03em;line-height:1.15}
.facts{display:grid;gap:8px;margin-top:16px}
.fact{display:grid;grid-template-columns:18px minmax(0,1fr);gap:9px;color:var(--_text);font-size:13px;line-height:1.45}
.icon{color:var(--_accent);font-size:13px;font-weight:850;text-align:center}
.muted{display:block;color:var(--_muted);font-size:11px}
.description{margin:17px 0 0;color:var(--_muted);font-size:13px;line-height:1.6}
.tags{display:flex;flex-wrap:wrap;gap:7px;margin-top:17px}
