const title=typeof data.title==='string'&&data.title.trim()?data.title.trim():'Untitled event';
const date=data.date&&typeof data.date==='object'?data.date:{};
const time=data.time&&typeof data.time==='object'?data.time:{};
const location=data.location&&typeof data.location==='object'?data.location:{};
const frame=make('article','frame'); frame.setAttribute('aria-label',title);
const cover=make('div','cover');
if(data.cover&&data.cover.src){ const image=make('img'); image.src=String(data.cover.src); image.alt=data.cover.alt?String(data.cover.alt):''; image.loading='lazy'; cover.appendChild(image); }
