dateBadge.appendChild(make('span','weekday',[date.weekday,date.year].filter(Boolean).join(' · ')||'TBA')); content.appendChild(dateBadge);
const details=make('div'); details.appendChild(make('div','eyebrow',data.eyebrow?String(data.eyebrow):'Upcoming event')); details.appendChild(make('h2','',title));
const facts=make('div','facts');
const timeParts=[time.start,time.end].filter(Boolean).map(String); if(timeParts.length){ const fact=make('div','fact'); fact.appendChild(make('span','icon','◷')); const copy=make('div','',timeParts.join(' – ')); if(time.timezone) copy.appendChild(make('span','muted',String(time.timezone))); fact.appendChild(copy); facts.appendChild(fact); }
if(location.name||location.address){ const fact=make('div','fact'); fact.appendChild(make('span','icon','◆')); const copy=make('div','',location.name?String(location.name):'Location TBA'); if(location.address) copy.appendChild(make('span','muted',String(location.address))); fact.appendChild(copy); facts.appendChild(fact); }
details.appendChild(facts);
if(data.description) details.appendChild(make('p','description',String(data.description)));
const tags=Array.isArray(data.tags)?data.tags:[]; if(tags.length){ const tagList=make('div','tags'); tags.forEach((tag) => tagList.appendChild(make('span','tag',String(tag)))); details.appendChild(tagList); }
content.appendChild(details); frame.appendChild(content); root.appendChild(frame);
parent.appendChild(host);

